(() => { const header = document.querySelector('.site-header'); const navToggle = document.querySelector('.nav-toggle'); const siteNav = document.querySelector('.site-nav'); const navLinks = document.querySelectorAll('.site-nav a'); const backToTop = document.getElementById('back-to-top'); const sections = document.querySelectorAll('section[id]'); const contactForm = document.getElementById('contact-form'); navToggle.addEventListener('click', () => { const expanded = navToggle.getAttribute('aria-expanded') === 'true'; navToggle.setAttribute('aria-expanded', String(!expanded)); siteNav.classList.toggle('is-open'); navToggle.classList.toggle('is-active'); }); navLinks.forEach((link) => { link.addEventListener('click', () => { navToggle.setAttribute('aria-expanded', 'false'); siteNav.classList.remove('is-open'); navToggle.classList.remove('is-active'); }); }); let scrollTicking = false; const onScroll = () => { header.classList.toggle('is-scrolled', window.scrollY > 20); backToTop.classList.toggle('is-visible', window.scrollY > 500); let current = ''; sections.forEach((section) => { const top = section.offsetTop - 120; if (window.scrollY >= top) current = section.id; }); navLinks.forEach((link) => { link.classList.toggle('is-active', link.getAttribute('href') === `#${current}`); }); scrollTicking = false; }; window.addEventListener('scroll', () => { if (!scrollTicking) { scrollTicking = true; requestAnimationFrame(onScroll); } }, { passive: true }); onScroll(); backToTop.addEventListener('click', () => { window.scrollTo({ top: 0, behavior: 'smooth' }); }); const revealEls = document.querySelectorAll('.reveal'); if (revealEls.length) { const observer = new IntersectionObserver((entries, obs) => { entries.forEach((entry) => { if (entry.isIntersecting) { entry.target.classList.add('is-visible'); obs.unobserve(entry.target); } }); }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' }); revealEls.forEach((el) => observer.observe(el)); } if (contactForm) { contactForm.addEventListener('submit', (e) => { e.preventDefault(); const name = document.getElementById('name').value.trim(); const email = document.getElementById('email').value.trim(); const subject = document.getElementById('subject').value.trim() || 'Portfolio Inquiry'; const message = document.getElementById('message').value.trim(); const body = `Name: ${name}\nEmail: ${email}\n\n${message}`; window.location.href = `mailto:3omarabdelaziz123@gmail.com?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`; }); } })();